arguments.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX fq: <https://www.purl.org/futuram/query#>
SELECT ?cls ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)), "battery-electric vehicle") && CONTAINS(LCASE(STR(?label)), "segment c") )
}
LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX fq: <https://www.purl.org/futuram/query#>
SELECT ?cls ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)), "battery-electric vehicle") )
  FILTER( CONTAINS(LCASE(STR(?comment)), "passenger") || CONTAINS(LCASE(STR(?comment)), "directly") || !BOUND(?comment) )
}
ORDER BY ?label
LIMIT 30

