PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rdf:     <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?node ?type ?label ?itemMass WHERE {
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030102_Y2025> ;
        rdf:type        ?type ;
        fq:itemMass     ?itemMass .
  OPTIONAL { ?type rdfs:label ?label }
}
ORDER BY DESC(?itemMass)
LIMIT 50

