        rdf:type ?ctype ;
        fq:itemMass ?mass .
} ORDER BY DESC(?mass)

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?cls ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)), "motor") ||
          CONTAINS(LCASE(STR(?comment)), "motor") ||
          CONTAINS(LCASE(STR(?label)), "magnet") ||
          CONTAINS(LCASE(STR(?comment)), "magnet") )
} LIMIT 50

