SELECT ?amt (SAMPLE(?frac) AS ?frac) (SAMPLE(?m) AS ?m) (SAMPLE(?relU) AS ?relU) (SAMPLE(?consName) AS ?consName) WHERE {
  {
    SELECT ?amt ?cons ?frac ?m ?relU WHERE {
