           fq:amount ?frac ;
           fq:relativeUncertainty ?relU .
      ?cons rdfs:subClassOf* <http://purl.obolibrary.org/obo/CHEBI_33321> .
    }
  }
  BIND(REPLACE(STR(?cons), "^.*#", "") AS ?consName)
} GROUP BY ?amt ORDER BY DESC(?m * ?frac)

