PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?cls ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label   ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)),   "bev") || CONTAINS(LCASE(STR(?label)), "battery") || CONTAINS(LCASE(STR(?comment)), "bev") )
  FILTER( CONTAINS(LCASE(STR(?label)),  "segment c") || CONTAINS(LCASE(STR(?comment)), "segment c") || CONTAINS(LCASE(STR(?label)),  "compact") )
}
ORDER BY ?cls

