  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label   ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)),   "id.3") || CONTAINS(LCASE(STR(?comment)), "id.3") || CONTAINS(LCASE(STR(?comment)), "id3") || CONTAINS(LCASE(STR(?label)), "id3") )
}

