arguments.sparql_query:
PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>

# Compute kg of each REE in the BEV 2025 permanent-magnet electric motor (itemMass * amount)
SELECT ?key ?kg WHERE {
  futuram:elvBEV_elvElectricMotor_Y2025 fq:itemMass ?m ;
    fq:contains [ fq:constituent ?key ; fq:amount ?f ] .
  FILTER(?key IN (futuram:Neodymium, futuram:Dysprosium, futuram:Praseodymium))
  BIND(?m * ?f AS ?kg)
}

PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>

# Total REE kg in the BEV 2025 motor (sum of Nd+Dy+Pr)
SELECT (SUM(?kg) AS ?totalREE_kg) WHERE {
  futuram:elvBEV_elvElectricMotor_Y2025 fq:itemMass ?m ;
    fq:contains [ fq:constituent ?key ; fq:amount ?f ] .
  FILTER(?key IN (futuram:Neodymium, futuram:Dysprosium, futuram:Praseodymium))
  BIND(?m * ?f AS ?kg)
}

